#include <stdio.h>

// 8-to-3 Priority Encoder Function
void priority_encoder_8to3(int inputs[], int outputs[], int *valid) {
    // Check if any input is active
    *valid = 0;
    for (int i = 0; i < 8; i++) {
        if (inputs[i]) {
            *valid = 1;
            // Higher index = higher priority
            outputs[2] = (i >= 4);  // Y2
            outputs[1] = ((i >= 2) && (i < 4)) || ((i >= 6) && (i < 8));  // Y1
            outputs[0] = (i % 2 == 1);  // Y0
            break;  // Exit after finding highest priority
        }
    }

    if (!*valid) {
        outputs[0] = outputs[1] = outputs[2] = 0;
    }
}

int main() {
    int inputs[8], outputs[3], valid;

    // Test: Input I5 is active (binary 101 = 5)
    // Expected output: 101
    for (int i = 0; i < 8; i++) inputs[i] = 0;
    inputs[5] = 1;

    priority_encoder_8to3(inputs, outputs, &valid);

    printf("Priority Encoder 8-to-3\n");
    printf("Input: I5 = 1\n");
    printf("Valid: %d\n", valid);
    printf("Output: %d%d%d\n", outputs[2], outputs[1], outputs[0]);

    return 0;
}

public class Encoder4to2 {
    private boolean enable;

    public Encoder4to2() {
        this.enable = true;  // Default enabled
    }

    public void setEnable(boolean enable) {
        this.enable = enable;
    }

    public int[] encode(int[] inputs) {
        // Output array: [Y1, Y0]
        int[] outputs = {0, 0};

        // If encoder is disabled, return all zeros
        if (!enable) {
            return outputs;
        }

        // Check for valid input (exactly one HIGH)
        int count = 0;
        for (int input : inputs) {
            count += input;
        }

        if (count != 1) {
            System.out.println("Warning: Invalid input - multiple or no inputs active");
            return outputs;
        }

        // Y1 = I3 + I2
        outputs[0] = (inputs[0] == 1 || inputs[1] == 1) ? 1 : 0;

        // Y0 = I3 + I1
        outputs[1] = (inputs[0] == 1 || inputs[2] == 1) ? 1 : 0;

        return outputs;
    }

    public static void main(String[] args) {
        Encoder4to2 encoder = new Encoder4to2();

        // Test input I2 = 1 (binary 0100, should give output 10)
        int[] input = {0, 1, 0, 0};
        int[] output = encoder.encode(input);

        System.out.println("4-to-2 Encoder Test");
        System.out.println("Input: I2 = 1");
        System.out.println("Output: Y1Y0 = " + output[0] + output[1]);
        System.out.println("Expected: 10");
    }
}
